+        let copySpaces = loadSymbol("CGSCopySpacesForWindows", as: CGSCopySpacesForWindowsFunc.self),
+        let getActiveSpace = loadSymbol("CGSGetActiveSpace", as: CGSGetActiveSpaceFunc.self)
